<?php
declare(strict_types=1);
namespace Ostoya\ShoppingList\Model\Resolver; use Magento\Framework\GraphQl\Config\Element\Field;use Magento\Framework\GraphQl\Query\ResolverInterface;use Magento\Framework\GraphQl\Schema\Type\ResolveInfo;use Psr\Log\LoggerInterface;use Ostoya\ShoppingList\Model\Service\ShoppingListService;
class CreateShoppingList implements ResolverInterface{public function __construct(private readonly CustomerContext $customerContext,private readonly ShoppingListService $service,private readonly ResolverDataFormatter $formatter,private readonly LoggerInterface $logger){} public function resolve(Field $field,$context,ResolveInfo $info,array $value=null,array $args=null): array{try{$list=$this->service->createList($this->customerContext->getCustomerId($context),(string)$args['input']['list_name']);return ['success'=>true,'message'=>'Shopping list created.','list'=>$this->formatter->formatList($list,[])];}catch(\Throwable $e){$this->logger->error($e->getMessage());throw $e;}}}
